  const handleGoalChange = (val: string) => {
    const num = parseInt(val) || 0;
    onUpdateStats({ dailyGoal: num });
  };

  const handleNameChange = (val: string) => {
    onUpdate({ name: val });
  };

  const activityData = React.useMemo(() => {
    const counts = new Array(7).fill(0);
    const now = new Date();
    const today = now.getDay();

    meals.forEach(m => {
      const mealDate = m.timestamp ? new Date(m.timestamp) : new Date();
      const diff = Math.floor((now.getTime() - mealDate.getTime()) / (1000 * 60 * 60 * 24));
      if (diff < 7) {
        const day = mealDate.getDay();
        counts[day] += 1;
      }
    });
    return counts;
  }, [meals]);

  return (
    <div className="flex flex-col w-full pb-40 animate-in fade-in duration-500">
      {/* Header Profile Section */}
      <div className="relative pt-16 pb-10 px-8 flex flex-col items-center">
