          <button className="absolute -bottom-2 -right-2 size-10 bg-primary text-white rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-all">
            <span className="material-symbols-outlined text-[20px]">photo_camera</span>
          </button>
        </div>

        <div className="mt-6 text-center w-full max-w-xs">
          <input
            type="text"
            value={profile.name}
            onChange={(e) => handleNameChange(e.target.value)}
            className="bg-transparent border-none text-center text-2xl font-black text-charcoal dark:text-white focus:ring-0 w-full"
          />
          <p className="text-muted-green dark:text-gray-400 text-xs font-bold uppercase tracking-[0.2em] mt-1">Premium Member</p>
        </div>
      </div>

      {/* Daily Goal Card */}
      <div className="px-6 mb-8">
        <div className="bg-white dark:bg-white/5 border border-gray-100 dark:border-white/10 rounded-[2.5rem] p-8 shadow-soft">
