               <span className="text-[10px] font-bold text-primary ml-1 uppercase">kcal</span>
            </div>
          </div>
        </div>
      </div>

      {/* Preferred Cuisine Grid */}
      <div className="px-6 mb-10">
        <h3 className="text-lg font-black dark:text-white mb-6 px-2 flex items-center gap-2">
          <span className="material-symbols-outlined text-primary">restaurant</span>
          Cuisine Preferences
