                <span className="material-symbols-outlined text-[22px]">{cuisine.icon}</span>
              </div>
              <span className="font-bold text-sm tracking-tight">{cuisine.name}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Activity Tracker */}
      <div className="px-6 mb-8">
        <div className="bg-gray-50 dark:bg-white/5 rounded-[2.5rem] p-8 border border-gray-100 dark:border-white/5">
